#### Indicadores


::: {.cell}

```{.r .cell-code  code-fold="true"}
library(gt)

# Carregar indicadores baseados em eventos e filtrar o ano
zen_file(18612340, "tmax_monthly_indi_n1981_2010.parquet") |>
  open_dataset() |>
  filter(code_muni == 3304557) |>
  filter(year == 2024) |>
  select(-code_muni, -year) |>
  collect() |>
  gt() |>
  fmt_number(
    columns = where(is.double),
    decimals = 2,
    use_seps = FALSE
  )
```

